/**
 * Chapter figure images for `/content/*` routes.
 *
 * Set `NEXT_PUBLIC_OCI_IMAGE_BASE` to your public Object Storage path prefix (no trailing slash):
 *   https://objectstorage.<region>.oraclecloud.com/n/<namespace>/b/<bucket>/o
 *
 * Upload objects with: `node scripts/upload-content-images-to-oci.mjs`
 * Regenerate this file after changing URLs: `node scripts/generate-content-images.mjs`
 */

export function buildChapterImageUrl(objectPath: string, legacyUrl: string): string {
  const raw =
    typeof process !== "undefined" &&
    typeof process.env !== "undefined" &&
    process.env.NEXT_PUBLIC_OCI_IMAGE_BASE
      ? String(process.env.NEXT_PUBLIC_OCI_IMAGE_BASE).replace(/\/$/, "")
      : "";
  if (!raw) return legacyUrl;
  return `${raw}/${encodeURIComponent(objectPath)}`;
}

